(function () {
  function addStyle(){ if(document.getElementById('lgb-style'))return; var s=document.createElement('style'); s.id='lgb-style'; s.textContent='.lgb-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.lgb-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px}.lgb-card{background:#f8fafc;border:1px solid #e5e7eb;border-radius:10px;padding:12px}.lgb-switch{display:inline-flex;gap:8px;align-items:center;margin-right:12px}.lgb-gate{height:96px;border:3px solid #007bff;border-left-width:10px;border-radius:18px 42px 42px 18px;display:flex;align-items:center;justify-content:center;font-size:28px;font-weight:700;color:#007bff;background:#fff}.lgb-on{background:#d4edda;border-left:4px solid #28a745;padding:10px;border-radius:8px}.lgb-table{width:100%;border-collapse:collapse}.lgb-table td,.lgb-table th{border:1px solid #e5e7eb;padding:5px;text-align:center}'; document.head.appendChild(s); }
  function mount(host){ if(!host||host.dataset.lgbMounted)return; host.dataset.lgbMounted='1'; addStyle(); var gates=['AND','OR','NOT','NAND','NOR','XOR','XNOR']; host.innerHTML='<div class="lgb-wrap"><h4>🔌 Bộ dựng cổng logic</h4><label class="lgb-switch">x <input data-x type="checkbox"></label><label class="lgb-switch">y <input data-y type="checkbox" checked></label><select data-g>'+gates.map(function(g){return '<option>'+g+'</option>';}).join('')+'</select><div class="lgb-grid"><div class="lgb-card"><div class="lgb-gate"></div><div class="lgb-on"></div></div><div class="lgb-card"><strong>Bảng chân trị</strong><div data-table></div></div><div class="lgb-card"><strong>Tối thiểu hóa mẫu</strong><p>F = xy + xy\' + x\'y</p><p><strong>F = x + y</strong></p><p>Ba minterm phủ mọi trường hợp trừ 00, nên rút thành OR.</p></div></div></div>'; function calc(g,x,y){ if(g==='AND')return x&&y; if(g==='OR')return x||y; if(g==='NOT')return !x; if(g==='NAND')return !(x&&y); if(g==='NOR')return !(x||y); if(g==='XOR')return x!==y; return x===y; } function paint(){var x=host.querySelector('[data-x]').checked,y=host.querySelector('[data-y]').checked,g=host.querySelector('[data-g]').value,o=calc(g,x,y)?1:0; host.querySelector('.lgb-gate').textContent=g; host.querySelector('.lgb-on').innerHTML='Với x='+(x?1:0)+', y='+(y?1:0)+' ⇒ đầu ra = <strong>'+o+'</strong>'; host.querySelector('[data-table]').innerHTML='<table class="lgb-table"><tr><th>x</th><th>y</th><th>F</th></tr>'+[[0,0],[0,1],[1,0],[1,1]].map(function(r){return '<tr><td>'+r[0]+'</td><td>'+r[1]+'</td><td>'+Number(calc(g,!!r[0],!!r[1]))+'</td></tr>';}).join('')+'</table>';} host.querySelectorAll('input,select').forEach(function(e){e.addEventListener('change',paint);}); paint(); }
  document.addEventListener('DOMContentLoaded',function(){document.querySelectorAll('[data-demo="logic-gates-builder"]').forEach(mount);});
}());
